contracts/Disburse.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title Disburse
 * @notice Handles cUSD disbursements to beneficiary wallets.
 *         Agencies deposit cUSD into this contract, then disburse to beneficiaries.
 *         Every disbursement is logged on-chain for full transparency.
 */
contract Disburse is AccessControl, Pausable, ReentrancyGuard {

    bytes32 public constant AGENCY_ROLE = keccak256("AGENCY_ROLE");
    bytes32 public constant ADMIN_ROLE  = keccak256("ADMIN_ROLE");

    // cUSD contract address on Celo
    // Alfajores testnet: 0x874069Fa1Eb16D44d622F2e0Ca25eeA172369bC1
    // Mainnet:           0x765DE816845861e75A25fCA122bb6898B8B1282a
    IERC20 public immutable cUSD;

    // PassportRegistry address — used to verify DID exists
    address public passportRegistry;

    // ─── STRUCTS ─────────────────────────────────────────────────────

    struct DisbursementRecord {
        string  did;
        address recipient;
        uint256 amount;
        string  reason;
        address agency;
        uint256 timestamp;
    }

    // ─── STORAGE ─────────────────────────────────────────────────────

    // Agency => their deposited cUSD balance in this contract
    mapping(address => uint256) public agencyBalances;

    // did => total disbursed to this passport
    mapping(string => uint256) public totalDisbursedToDid;

    // All disbursement records
    DisbursementRecord[] public disbursements;

    // ─── EVENTS ──────────────────────────────────────────────────────

    event Deposited(address indexed agency, uint256 amount);
    event Disbursed(
        string  indexed did,
        address indexed recipient,
        address indexed agency,
        uint256 amount,
        string  reason,
        uint256 timestamp
    );
    event Withdrawn(address indexed agency, uint256 amount);

    // ─── CONSTRUCTOR ─────────────────────────────────────────────────

    constructor(address admin, address cUSDAddress, address _passportRegistry) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
        cUSD = IERC20(cUSDAddress);
        passportRegistry = _passportRegistry;
    }

    // ─── AGENCY FUNDING ──────────────────────────────────────────────

    /**
     * @notice Agency deposits cUSD into the contract to fund disbursements
     * @dev Agency must approve this contract to spend cUSD first
     */
    function deposit(uint256 amount)
        external
        onlyRole(AGENCY_ROLE)
        whenNotPaused
    {
        require(amount > 0, "Amount must be > 0");
        require(
            cUSD.transferFrom(msg.sender, address(this), amount),
            "cUSD transfer failed"
        );
        agencyBalances[msg.sender] += amount;
        emit Deposited(msg.sender, amount);
    }

    // ─── DISBURSEMENT ─────────────────────────────────────────────────

    /**
     * @notice Disburse cUSD to a beneficiary wallet
     * @param did            Beneficiary passport DID
     * @param recipient      Beneficiary's Celo wallet address
     * @param amount         Amount in cUSD (18 decimals)
     * @param reason         Reason string (e.g. "monthly_food_voucher")
     */
    function disburse(
        string calldata did,
        address recipient,
        uint256 amount,
        string calldata reason
    )
        external
        onlyRole(AGENCY_ROLE)
        whenNotPaused
        nonReentrant
    {
        require(amount > 0, "Amount must be > 0");
        require(recipient != address(0), "Invalid recipient");
        require(agencyBalances[msg.sender] >= amount, "Insufficient agency balance");
        require(bytes(did).length > 0, "DID required");

        agencyBalances[msg.sender] -= amount;
        totalDisbursedToDid[did] += amount;

        disbursements.push(DisbursementRecord({
            did:       did,
            recipient: recipient,
            amount:    amount,
            reason:    reason,
            agency:    msg.sender,
            timestamp: block.timestamp
        }));

        require(cUSD.transfer(recipient, amount), "cUSD transfer failed");

        emit Disbursed(did, recipient, msg.sender, amount, reason, block.timestamp);
    }

    // ─── VIEW FUNCTIONS ───────────────────────────────────────────────

    /**
     * @notice Total number of disbursements ever made
     */
    function totalDisbursements() external view returns (uint256) {
        return disbursements.length;
    }

    /**
     * @notice Get a specific disbursement record
     */
    function getDisbursement(uint256 index)
        external
        view
        returns (DisbursementRecord memory)
    {
        require(index < disbursements.length, "Index out of bounds");
        return disbursements[index];
    }

    /**
     * @notice Get total cUSD disbursed across all agencies
     */
    function totalDisbursedAllTime() external view returns (uint256) {
        uint256 total = 0;
        for (uint256 i = 0; i < disbursements.length; i++) {
            total += disbursements[i].amount;
        }
        return total;
    }

    // ─── AGENCY WITHDRAWAL ───────────────────────────────────────────

    /**
     * @notice Agency can withdraw unspent cUSD balance
     */
    function withdraw(uint256 amount)
        external
        onlyRole(AGENCY_ROLE)
        nonReentrant
    {
        require(agencyBalances[msg.sender] >= amount, "Insufficient balance");
        agencyBalances[msg.sender] -= amount;
        require(cUSD.transfer(msg.sender, amount), "Transfer failed");
        emit Withdrawn(msg.sender, amount);
    }

    // ─── ADMIN ───────────────────────────────────────────────────────

    function registerAgency(address agency) external onlyRole(ADMIN_ROLE) {
        _grantRole(AGENCY_ROLE, agency);
    }

    function pause()   external onlyRole(ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(ADMIN_ROLE) { _unpause(); }
}

contracts/OracleCore.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title OracleCore
 * @notice Crisis oracle contracts for anticipatory action.
 *         Agencies define trigger conditions. When data from
 *         Chainlink or OCHA APIs crosses a threshold, this
 *         contract auto-disburses cUSD to all affected families.
 *
 * @dev In production, integrate with Chainlink Functions for
 *      off-chain data. For the UNICEF prototype demo, the
 *      triggerOracle() function is called by a trusted backend
 *      service that monitors OCHA/USGS data feeds.
 */
contract OracleCore is AccessControl, Pausable, ReentrancyGuard {

    bytes32 public constant AGENCY_ROLE   = keccak256("AGENCY_ROLE");
    bytes32 public constant ORACLE_ROLE   = keccak256("ORACLE_ROLE"); // backend data service
    bytes32 public constant ADMIN_ROLE    = keccak256("ADMIN_ROLE");

    // ─── STRUCTS ─────────────────────────────────────────────────────

    struct OracleConfig {
        string   name;
        string   dataSource;       // e.g. "ocha_hdx_flood_index"
        string   condition;        // human-readable condition description
        uint256  disburseCusd;     // amount per family in wei (18 decimals)
        string   scopeDistrict;    // district name for scoping
        uint256  checkIntervalSec; // how often backend should check (seconds)
        address  agencyAddress;
        bool     active;
        uint256  createdAt;
        uint256  lastTriggeredAt;
        uint256  triggerCount;
    }

    struct TriggerEvent {
        uint256 oracleId;
        uint256 timestamp;
        uint256 familiesAffected;
        uint256 totalDisbursed;
        string  dataValue;         // the value that triggered (e.g. "0.82")
        address triggeredBy;
    }

    // ─── STORAGE ─────────────────────────────────────────────────────

    OracleConfig[] public oracles;
    TriggerEvent[] public triggerHistory;

    // ─── EVENTS ──────────────────────────────────────────────────────

    event OracleDeployed(
        uint256 indexed oracleId,
        string name,
        address indexed agency,
        uint256 disburseCusd
    );

    event OracleTriggered(
        uint256 indexed oracleId,
        uint256 familiesAffected,
        uint256 totalDisbursed,
        string dataValue,
        uint256 timestamp
    );

    event OracleDeactivated(uint256 indexed oracleId);

    // ─── CONSTRUCTOR ─────────────────────────────────────────────────

    constructor(address admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
        _grantRole(ORACLE_ROLE, admin); // admin can trigger manually
    }

    // ─── ORACLE MANAGEMENT ───────────────────────────────────────────

    /**
     * @notice Agency deploys a new crisis oracle configuration
     */
    function deployOracle(
        string calldata name,
        string calldata dataSource,
        string calldata condition,
        uint256 disburseCusd,
        string calldata scopeDistrict,
        uint256 checkIntervalSec
    )
        external
        onlyRole(AGENCY_ROLE)
        whenNotPaused
        returns (uint256 oracleId)
    {
        require(disburseCusd > 0, "Disburse amount required");
        require(bytes(name).length > 0, "Name required");

        oracleId = oracles.length;

        oracles.push(OracleConfig({
            name:             name,
            dataSource:       dataSource,
            condition:        condition,
            disburseCusd:     disburseCusd,
            scopeDistrict:    scopeDistrict,
            checkIntervalSec: checkIntervalSec,
            agencyAddress:    msg.sender,
            active:           true,
            createdAt:        block.timestamp,
            lastTriggeredAt:  0,
            triggerCount:     0
        }));

        emit OracleDeployed(oracleId, name, msg.sender, disburseCusd);
    }

    /**
     * @notice Called by backend oracle service when trigger condition is met
     * @param oracleId        Oracle configuration ID
     * @param familiesAffected Number of families to receive disbursement
     * @param dataValue       The data value that triggered (for audit trail)
     */
    function triggerOracle(
        uint256 oracleId,
        uint256 familiesAffected,
        string calldata dataValue
    )
        external
        onlyRole(ORACLE_ROLE)
        whenNotPaused
        nonReentrant
    {
        require(oracleId < oracles.length, "Oracle not found");
        OracleConfig storage oracle = oracles[oracleId];
        require(oracle.active, "Oracle not active");
        require(familiesAffected > 0, "No families affected");

        uint256 totalDisbursed = oracle.disburseCusd * familiesAffected;

        oracle.lastTriggeredAt = block.timestamp;
        oracle.triggerCount++;

        triggerHistory.push(TriggerEvent({
            oracleId:         oracleId,
            timestamp:        block.timestamp,
            familiesAffected: familiesAffected,
            totalDisbursed:   totalDisbursed,
            dataValue:        dataValue,
            triggeredBy:      msg.sender
        }));

        emit OracleTriggered(
            oracleId,
            familiesAffected,
            totalDisbursed,
            dataValue,
            block.timestamp
        );

        // NOTE: Actual cUSD transfer is handled by the Disburse contract.
        // This contract records the trigger event on-chain for transparency.
        // The backend service calls Disburse.disburse() for each affected family.
    }

    // ─── VIEW FUNCTIONS ───────────────────────────────────────────────

    function getOracle(uint256 oracleId)
        external
        view
        returns (OracleConfig memory)
    {
        require(oracleId < oracles.length, "Oracle not found");
        return oracles[oracleId];
    }

    function totalOracles() external view returns (uint256) {
        return oracles.length;
    }

    function totalTriggers() external view returns (uint256) {
        return triggerHistory.length;
    }

    function getTriggerEvent(uint256 index)
        external
        view
        returns (TriggerEvent memory)
    {
        require(index < triggerHistory.length, "Index out of bounds");
        return triggerHistory[index];
    }

    // ─── ADMIN ───────────────────────────────────────────────────────

    function deactivateOracle(uint256 oracleId) external {
        require(oracleId < oracles.length, "Oracle not found");
        require(
            oracles[oracleId].agencyAddress == msg.sender ||
            hasRole(ADMIN_ROLE, msg.sender),
            "Not authorized"
        );
        oracles[oracleId].active = false;
        emit OracleDeactivated(oracleId);
    }

    function registerAgency(address agency) external onlyRole(ADMIN_ROLE) {
        _grantRole(AGENCY_ROLE, agency);
    }

    function registerOracleService(address service) external onlyRole(ADMIN_ROLE) {
        _grantRole(ORACLE_ROLE, service);
    }

    function pause()   external onlyRole(ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(ADMIN_ROLE) { _unpause(); }
}

contracts/PassportRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";

/**
 * @title PassportRegistry
 * @notice Core ImpactChain protocol contract.
 *         Stores Beneficiary Passport DIDs on Celo.
 *         Any registered agency can create and update passports.
 *         No PII stored on-chain — only hashed identifiers and IPFS hashes.
 */
contract PassportRegistry is AccessControl, Pausable {

    bytes32 public constant AGENCY_ROLE = keccak256("AGENCY_ROLE");
    bytes32 public constant ADMIN_ROLE  = keccak256("ADMIN_ROLE");

    // ─── STRUCTS ─────────────────────────────────────────────────────

    struct Passport {
        bytes32 phoneHash;       // keccak256 of phone number — no raw PII on-chain
        string  did;             // W3C DID string: "did:ethr:celo:0x..."
        uint256 createdAt;
        uint256 updatedAt;
        uint8   childrenCount;
        bool    exists;
        address createdByAgency;
    }

    struct Credential {
        address agencyAddress;
        string  credentialType;  // e.g. "FoodAssistanceEligibility"
        string  ipfsHash;        // IPFS hash of the W3C VC payload
        uint256 issuedAt;
        uint256 validUntil;
        bool    revoked;
    }

    // ─── STORAGE ─────────────────────────────────────────────────────

    // did => Passport
    mapping(string => Passport) public passports;

    // did => list of credentials
    mapping(string => Credential[]) public credentials;

    // phoneHash => did (for lookup by phone)
    mapping(bytes32 => string) public phoneHashToDid;

    // Track all DIDs for enumeration
    string[] public allDids;

    // ─── EVENTS ──────────────────────────────────────────────────────

    event PassportCreated(
        string indexed did,
        bytes32 indexed phoneHash,
        address indexed agency,
        uint256 timestamp
    );

    event CredentialIssued(
        string indexed did,
        address indexed agency,
        string credentialType,
        string ipfsHash,
        uint256 timestamp
    );

    event CredentialRevoked(
        string indexed did,
        uint256 credentialIndex,
        address indexed agency
    );

    event AgencyRegistered(address indexed agency, string name);
    event AgencyRevoked(address indexed agency);

    // ─── AGENCY REGISTRY ─────────────────────────────────────────────

    struct Agency {
        string name;
        bool   active;
        uint256 registeredAt;
    }

    mapping(address => Agency) public agencies;

    // ─── CONSTRUCTOR ─────────────────────────────────────────────────

    constructor(address admin) {
        _grantRole(DEFAULT_ADMIN_ROLE, admin);
        _grantRole(ADMIN_ROLE, admin);
    }

    // ─── AGENCY MANAGEMENT ───────────────────────────────────────────

    /**
     * @notice Register a new humanitarian agency
     * @dev Only protocol admin can call this
     */
    function registerAgency(address agencyAddress, string calldata name)
        external
        onlyRole(ADMIN_ROLE)
    {
        agencies[agencyAddress] = Agency({
            name: name,
            active: true,
            registeredAt: block.timestamp
        });
        _grantRole(AGENCY_ROLE, agencyAddress);
        emit AgencyRegistered(agencyAddress, name);
    }

    /**
     * @notice Revoke an agency's access
     */
    function revokeAgency(address agencyAddress)
        external
        onlyRole(ADMIN_ROLE)
    {
        agencies[agencyAddress].active = false;
        _revokeRole(AGENCY_ROLE, agencyAddress);
        emit AgencyRevoked(agencyAddress);
    }

    // ─── PASSPORT OPERATIONS ─────────────────────────────────────────

    /**
     * @notice Create a new Beneficiary Passport
     * @param phoneHash    keccak256 hash of beneficiary's phone number
     * @param did          W3C DID string
     * @param childrenCount Number of children under 18
     */
    function createPassport(
        bytes32 phoneHash,
        string calldata did,
        uint8 childrenCount
    )
        external
        onlyRole(AGENCY_ROLE)
        whenNotPaused
    {
        require(!passports[did].exists, "Passport already exists");
        require(bytes(phoneHashToDid[phoneHash]).length == 0, "Phone already registered");
        require(bytes(did).length > 0, "DID cannot be empty");

        passports[did] = Passport({
            phoneHash:       phoneHash,
            did:             did,
            createdAt:       block.timestamp,
            updatedAt:       block.timestamp,
            childrenCount:   childrenCount,
            exists:          true,
            createdByAgency: msg.sender
        });

        phoneHashToDid[phoneHash] = did;
        allDids.push(did);

        emit PassportCreated(did, phoneHash, msg.sender, block.timestamp);
    }

    /**
     * @notice Look up a DID by phone number hash
     */
    function getDidByPhone(bytes32 phoneHash)
        external
        view
        returns (string memory)
    {
        return phoneHashToDid[phoneHash];
    }

    /**
     * @notice Get passport data
     */
    function getPassport(string calldata did)
        external
        view
        returns (Passport memory)
    {
        require(passports[did].exists, "Passport not found");
        return passports[did];
    }

    /**
     * @notice Total number of passports created
     */
    function totalPassports() external view returns (uint256) {
        return allDids.length;
    }

    // ─── CREDENTIAL OPERATIONS ───────────────────────────────────────

    /**
     * @notice Issue a Verifiable Credential to a passport
     * @param did            Target passport DID
     * @param credentialType Type string (e.g. "FoodAssistanceEligibility")
     * @param ipfsHash       IPFS content hash of the full W3C VC JSON
     * @param validUntil     Unix timestamp of expiry
     */
    function issueCredential(
        string calldata did,
        string calldata credentialType,
        string calldata ipfsHash,
        uint256 validUntil
    )
        external
        onlyRole(AGENCY_ROLE)
        whenNotPaused
    {
        require(passports[did].exists, "Passport not found");
        require(bytes(ipfsHash).length > 0, "IPFS hash required");

        credentials[did].push(Credential({
            agencyAddress:  msg.sender,
            credentialType: credentialType,
            ipfsHash:       ipfsHash,
            issuedAt:       block.timestamp,
            validUntil:     validUntil,
            revoked:        false
        }));

        passports[did].updatedAt = block.timestamp;

        emit CredentialIssued(did, msg.sender, credentialType, ipfsHash, block.timestamp);
    }

    /**
     * @notice Get all credentials for a passport
     */
    function getCredentials(string calldata did)
        external
        view
        returns (Credential[] memory)
    {
        return credentials[did];
    }

    /**
     * @notice Get credential count for a passport
     */
    function getCredentialCount(string calldata did)
        external
        view
        returns (uint256)
    {
        return credentials[did].length;
    }

    /**
     * @notice Revoke a credential (only issuing agency can revoke)
     */
    function revokeCredential(string calldata did, uint256 index)
        external
        onlyRole(AGENCY_ROLE)
    {
        require(passports[did].exists, "Passport not found");
        require(index < credentials[did].length, "Credential index out of bounds");
        require(
            credentials[did][index].agencyAddress == msg.sender,
            "Only issuing agency can revoke"
        );

        credentials[did][index].revoked = true;
        emit CredentialRevoked(did, index, msg.sender);
    }

    // ─── ADMIN ───────────────────────────────────────────────────────

    function pause()   external onlyRole(ADMIN_ROLE) { _pause(); }
    function unpause() external onlyRole(ADMIN_ROLE) { _unpause(); }
}

